/**
 * WebAssembly Backend
 * Compiles Swibe to WebAssembly Text Format (WAT)
 */

export class WasmGenerator {
  constructor(ast) {
    this.ast = ast;
    this.functions = [];
    this.imports = [];
    this.exports = [];
    this.memory = true;
  }

  generate() {
    const funcs = this.ast.statements
      .filter(s => s.type === 'FunctionDecl')
      .map(f => this.genFunction(f))
      .join('\n  ');

    return `(module
    ;; Swibe WASM Runtime
      ;; Generated by Swibe compiler

        ;; Memory
          (memory (export "memory") 1)

            ;; Import host print function
              (import "host" "print" (func $host_print (param i32 i32)))

                ;; String storage offset
                  (global $str_offset (mut i32) (i32.const 0))

                    ${funcs}

                      ;; Main export
                        (export "main" (func $main))
                        )`;
  }

  genFunction(node) {
    const name = node.name || 'fn';
    const params = (node.params || [])
      .map(p => `(param $${p.name || p} i32)`)
      .join(' ');
    const body = this.genBlock(node.body);
    const isMain = name === 'main';

    return `
    (func $${name} ${params} ${isMain ? '' : '(result i32)'}
      ${body}
        ${isMain ? '' : '(i32.const 0)'}
          )`;
  }

  genBlock(node) {
    if (!node?.statements) return '';
    return node.statements
      .map(s => this.genStatement(s))
      .filter(Boolean)
      .join('\n    ');
  }

  genStatement(node) {
    if (!node) return '';
    switch(node.type) {
      case 'ThinkStatement':
        return `;; think: ${node.prompt?.value || ''}`;
      case 'BudgetStatement':
        return `;; budget: ${node.tokens} tokens`;
      case 'EvolveStatement':
        return `;; evolve soul`;
      case 'EthicsStatement':
        return `;; ethics enforced`;
      case 'FunctionCall':
        if (node.name === 'println' || node.name === 'print') {
          return `(call $host_print (i32.const 0) (i32.const 0))`;
        }
        return `(call $${node.name})`;
      case 'ReturnStatement':
        return `(return (i32.const 0))`;
      default:
        return `;; ${node.type}`;
    }
  }
}
